+    unsafe {
+        let attr = LandlockRulesetAttr {
+            handled_access_fs: 0xFFFF, // All access types
+        };
+        let fd = libc::syscall(
+            libc::SYS_landlock_create_ruleset,
+            &attr as *const _,
+            std::mem::size_of::<LandlockRulesetAttr>(),
+            0,
+        );
+        if fd >= 0 {
+            libc::close(fd as i32);
+            true
+        } else {
+            false
+        }
+    }
